import psycopg2
from psycopg2 import sql

def search_users(username=None, email=None, role=None, status=None):
    # Define allowed values for role and status
    allowed_roles = ['admin', 'user', 'guest']
    allowed_statuses = ['active', 'suspended']
    
    # Build the base query
    base_query = "SELECT * FROM users WHERE 1=1"
    params = []
    
    # Add filters if provided
    if username is not None:
        base_query += " AND username = %s"
        params.append(username)
    
    if email is not None:
        base_query += " AND email = %s"
        params.append(email)
    
    if role is not None:
        if role not in allowed_roles:
            raise ValueError(f"Invalid role: {role}. Must be one of {allowed_roles}")
        base_query += " AND role = %s"
        params.append(role)
    
    if status is not None:
        if status not in allowed_statuses:
            raise ValueError(f"Invalid status: {status}. Must be one of {allowed_statuses}")
        base_query += " AND status = %s"
        params.append(status)
    
    # Execute the query
    conn = psycopg2.connect(
        host="localhost",
        database="mydb",
        user="myuser",
        password="mypassword"
    )
    
    try:
        with conn.cursor() as cursor:
            cursor.execute(base_query, params)
            results = cursor.fetchall()
            return results
    finally:
        conn.close()